@vex_client.policy("gov-circular-dependency")
def prevent_circular_calls(ctx, agent: Agent, input_data):
    session_id = ctx.session_id
    call_stack = ctx.get_session_data('call_stack', [])

    if agent.name in call_stack[-3:]:
        ctx.block('Circular dependency detected')

    call_stack.append(agent.name)
    ctx.set_session_data('call_stack', call_stack)

    # Enforce max depth for government workflows
    if len(call_stack) > 5:
        ctx.block('Delegation depth exceeded')
    return True

@vex_client.policy("gov-explainability")
def capture_decision_trace(ctx, agent: Agent, input_data):
    # Track model versions across agents
    model_info = ctx.get_session_data('models_used', {})
    model_info[agent.name] = agent.model_version
    ctx.set_session_data('models_used', model_info)

    # Generate explainability report
    if 'final_decision' in input_data:
        trace = {
            'decision': input_data['final_decision'],
            'agents': ctx.get_session_data('call_stack'),
            'models': model_info,
            'timestamp': ctx.timestamp
        }
        ctx.log_audit('citizen_decision', trace)
    return True
